// Minimal CSS mode for Ace (small subset)
/* global ace */
ace.define('ace/mode/css_highlight_rules', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextHighlightRules = require('ace/mode/text_highlight_rules').TextHighlightRules;

  const CssHighlightRules = function () {
    this.$rules = {
      start: [
        { token: 'comment', start: '\\/\\*', end: '\\*\\/' },
        { token: 'string', regex: "'(?:\\\\.|[^'\\\\])*'" },
        { token: 'string', regex: '"(?:\\\\.|[^"\\\\])*"' },
        { token: 'constant.numeric', regex: '\\b\\d+(?:\\.\\d+)?(?:px|rem|em|%|vh|vw)?\\b' },
        { token: 'keyword', regex: '\\b(display|position|flex|grid|color|background|margin|padding|width|height|max-width|min-height|border|border-radius|gap|align-items|justify-content|font-size|font-weight|line-height)\\b' },
        { token: 'support.type', regex: '\\.[a-zA-Z0-9_-]+' },
        { token: 'support.type', regex: '\\#[a-zA-Z0-9_-]+' },
        { token: 'paren.lparen', regex: '[\\{\\(]' },
        { token: 'paren.rparen', regex: '[\\}\\)]' },
        { token: 'punctuation.operator', regex: '[:;,.>+~\\*]' },
        { token: 'text', regex: '\\s+' },
        { token: 'identifier', regex: '[a-zA-Z_-][a-zA-Z0-9_-]*' },
      ],
    };
  };
  oop.inherits(CssHighlightRules, TextHighlightRules);
  exports.CssHighlightRules = CssHighlightRules;
});

ace.define('ace/mode/css', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text', 'ace/mode/css_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextMode = require('ace/mode/text').Mode;
  const Rules = require('ace/mode/css_highlight_rules').CssHighlightRules;

  const Mode = function () {
    this.HighlightRules = Rules;
    this.$behaviour = this.$defaultBehaviour;
  };
  oop.inherits(Mode, TextMode);

  (function () {
    this.blockComment = { start: '/*', end: '*/' };
  }).call(Mode.prototype);

  exports.Mode = Mode;
});

